var path = require('path');
var filePath = '/User/nodePractice/projectfile1.html';

var fileName = path.basename(filePath);
console.log(fileName);
console.log("base name");

//  directory name
var dirName = path.dirname(filePath);
console.log(dirName);
console.log("dirName");

// extension name
var extName = path.extname(filePath);
console.log(extName);
console.log("extname");

// Formatting the path
var formattedPath = path.format({
    dir: '/User/nodePractice',
    base: 'projectfile1.html'
});
console.log(formattedPath);
console.log("format");

// Checking if the path is absolute
var isAbsolute = path.isAbsolute(filePath);
console.log(isAbsolute);
console.log("isAbsolute");

// Join the  paths
var joinedPath = path.join('/User', 'nodePractice', 'projectfile1.html');
console.log(joinedPath);
console.log("join");

// Normalizing the path
var normalizedPath = path.normalize('/User/nodePractice/projectfile1.html');
console.log(normalizedPath);
console.log("normalize");

// Parsing the path
var parsedPath = path.parse('/User/nodePractice/projectfile1.html');
console.log(parsedPath);
console.log("parse");

// Using POSIX path methods
var posixPath = path.posix;
console.log(posixPath);
console.log("posix");

// Getting the relative path
var relativePath = path.relative('/User/nodePractice', '/User/nodePractice/projectfile1.html');
console.log(relativePath);
console.log("relative");

// Resolving paths
var resolvedPath = path.resolve('path.js');
console.log(resolvedPath);
console.log("resolve");

// Getting the platform-specific path segment separator
var separator = path.sep;
console.log(separator);
console.log("sep");

// Using win32 path methods (for Windows)
var win32Path = path.win32;
console.log(win32Path);
console.log("win32");
